```c
/*libkmem_cache_free - free cache slot back to cache pool
 *@proc: process
 *@cache_pool_id: cache pool ID
 *@reg_index: register index containing the address to free
 */
int libkmem_cache_free(struct pcb_t *proc, uint32_t cache_pool_id, uint32_t reg_index)
{
    addr_t addr = proc->regs[reg_index];
    if (__kmem_cache_free(proc, 0, -1, cache_pool_id, addr) == 0) {
        return 0;
    }
    return -1;
}

/*__kmem_cache_free - free region memory back to kmem cache
 *@caller: caller
 *@vmaid: ID vm area
 *@rgid: memory region ID
 *@cache_pool_id: cache pool ID
 *@free_addr: address to free
 */
addr_t __kmem_cache_free(struct pcb_t *caller, int vmaid, int rgid, int cache_pool_id, addr_t free_addr)
{
    pthread_mutex_lock(&mmvm_lock);
    struct mm_struct *mm = caller->krnl->mm;
    struct kcache_pool_struct *pool = &mm->kcpooltbl[cache_pool_id];

    // Push the freed object to the front of the free list
    // Write the current storage pointer into the freed slot
    for (int i = 0; i < sizeof(addr_t); i++) {
        k_pg_setval(mm, free_addr + i, ((BYTE *)&pool->storage)[i], caller);
    }
    pool->storage = free_addr;

    pthread_mutex_unlock(&mmvm_lock);
    return 0;
}
```

### 4. Implement Slab Expansion
**File:

