// In __kmem_cache_alloc, replace the early return when storage == 0 with expansion
if (pool->storage == 0) {
    // Allocate a new slab
    addr_t new_slab_addr;
    if (__kmalloc(caller, vmaid, rgid, PAGING64_PAGESZ, &new_slab_addr) != 0) {
        pthread_mutex_unlock(&mmvm_lock);
        return -1;
    }

    // Track the new slab
    struct slab_struct *new_slab = malloc(sizeof(struct slab_struct));
    new_slab->addr = new_slab_addr;
    new_slab->next = pool->slabs;
    pool->slabs = new_slab;

    // Build free list for the new slab and prepend to existing free list
    int num_objs = PAGING64_PAGESZ / pool->size;
    for (int i = 0; i < num_objs; i++) {
        addr_t curr_slot = new_slab_addr + i * pool->size;
        addr_t next_slot = (i == num_objs - 1) ? pool->storage : (curr_slot + pool->size);
        for (int b = 0; b < sizeof(addr_t); b++) {
            k_pg_setval(mm, curr_slot + b, ((BYTE *)&next_slot)[b], caller);
        }
    }
    pool->storage = new_slab_addr;
}

